    public void start(int port) throws IOException {
        serverSocket = new ServerSocket(port);
        running = true;
        LOGGER.info("Enterprise SOAP Service started on port " + port);

        while (running) {
            try {
                Socket clientSocket = serverSocket.accept();
                executorService.submit(() -> handleClient(clientSocket));
            } catch (IOException e) {
                if (running) {
                    LOGGER.log(Level.SEVERE, "Error accepting connection", e);
                }
            }
        }
    }

    public void stop() {
        running = false;
        executorService.shutdown();
        try {
            if (serverSocket != null && !serverSocket.isClosed()) {
                serverSocket.close();
            }
            executorService.awaitTermination(30, TimeUnit.SECONDS);
        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "Error during shutdown", e);
        }
    }

    private void handleClient(Socket clientSocket) {
        try (InputStream inputStream = clientSocket.getInputStream();
             OutputStream outputStream = clientSocket.getOutputStream()) {

            String httpRequest = readHttpRequest(inputStream);
            String soapBody = extractSOAPBody(httpRequest);

            if (soapBody == null || soapBody.isEmpty()) {
                sendHttpResponse(outputStream, 400, createSOAPFault("Client", "Empty or invalid SOAP request"));
                return;
            }

            SOAPProcessingResult result = processSOAPMessage(soapBody);
            String responseXml = createSOAPResponse(result);
            sendHttpResponse(outputStream, 200, responseXml);

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error handling client request", e);
            try {
                sendHttpResponse(clientSocket.getOutputStream(), 500,
                        createSOAPFault("Server", "Internal server error: " + e.getMessage()));
            } catch (IOException ioe) {
                LOGGER.log(Level.SEVERE, "Error sending error response", ioe);
            }
        } finally {
            try {
                clientSocket.close();
            } catch (IOException e) {
                LOGGER.log(Level.WARNING, "Error closing client socket", e);
            }
        }
    }

    private String readHttpRequest(InputStream inputStream) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream));
        StringBuilder request = new StringBuilder();
        String line;
        int contentLength = 0;

        // Read headers
        while ((line = reader.readLine()) != null && !line.isEmpty()) {
            request.append(line).append("\r\n");
            if (line.toLowerCase().startsWith("content-length:")) {
                contentLength = Integer.parseInt(line.substring(15).trim());
            }
        }
        request.append("\r\n");

        // Read body
        if (contentLength > 0) {
            char[] body = new char[contentLength];
            int totalRead = 0;
            while (totalRead < contentLength) {
                int read = reader.read(body, totalRead, contentLength - totalRead);
                if (read == -1) break;
                totalRead += read;
            }
            request.append(new String(body, 0, totalRead));
        }

        return request.toString();
    }

    private String extractSOAPBody(String httpRequest) {
        int bodyStart = httpRequest.indexOf("<?xml");
        if (bodyStart == -1) {
            bodyStart = httpRequest.indexOf("<soap:");
            if (bodyStart == -1) {
                bodyStart = httpRequest.indexOf("<SOAP-ENV:");
                if (bodyStart == -1) {
                    bodyStart = httpRequest.indexOf("<soapenv:");
                }
            }
        }
        if (bodyStart == -1) return null;
        return httpRequest.substring(bodyStart);
    }

    public SOAPProcessingResult processSOAPMessage(String soapXml) {
        SOAPProcessingResult result = new SOAPProcessingResult();
        long startTime = System.currentTimeMillis();

        try {
            DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
            builder.setErrorHandler(new XMLErrorHandler());

            Document document = builder.parse(new InputSource(new StringReader(soapXml)));
            document.getDocumentElement().normalize();

            Element root = document.getDocumentElement();
            LOGGER.info("Processing SOAP message with root element: " + root.getNodeName());

            // Extract SOAP Header
            NodeList headerNodes = findElementsByLocalName(document, "Header");
            if (headerNodes.getLength() > 0) {
                processSOAPHeader((Element) headerNodes.item(0), result);
            }

            // Extract SOAP Body
            NodeList bodyNodes = findElementsByLocalName(document, "Body");
            if (bodyNodes.getLength() > 0) {
                Element bodyElement = (Element) bodyNodes.item(0);
                processSOAPBody(bodyElement, result);
            } else {
                result.setStatus("ERROR");
                result.addError("No SOAP Body element found");
            }

        } catch (SAXException e) {
            LOGGER.log(Level.SEVERE, "XML parsing error", e);
            result.setStatus("ERROR");
            result.addError("XML parsing error: " + e.getMessage());
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing SOAP message", e);
            result.setStatus("ERROR");
            result.addError("Processing error: " + e.getMessage());
        }

        result.setProcessingTimeMs(System.currentTimeMillis() - startTime);
        return result;
    }

    private NodeList findElementsByLocalName(Document document, String localName) {
        NodeList nodes = document.getElementsByTagNameNS("http://schemas.xmlsoap.org/soap/envelope/", localName);
        if (nodes.getLength() == 0) {
            nodes = document.getElementsByTagNameNS("http://www.w3.org/2003/05/soap-envelope", localName);
        }
        return nodes;
    }

    private void processSOAPHeader(Element headerElement, SOAPProcessingResult result) {
        NodeList children = headerElement.getChildNodes();
        Map<String, String> headerInfo = new LinkedHashMap<>();

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) child;
                headerInfo.put(element.getLocalName(), element.getTextContent().trim());
            }
        }

        result.setHeaderInfo(headerInfo);
        LOGGER.info("Processed SOAP headers: " + headerInfo.keySet());
    }

    private void processSOAPBody(Element bodyElement, SOAPProcessingResult result) {
        NodeList operations = bodyElement.getChildNodes();

        for (int i = 0; i < operations.getLength(); i++) {
            Node operationNode = operations.item(i);
            if (operationNode.getNodeType() != Node.ELEMENT_NODE) continue;

            Element operationElement = (Element) operationNode;
            String operationName = operationElement.getLocalName();
            LOGGER.info("Processing operation: " + operationName);

            switch (operationName) {
                case "DataImportRequest":
                    processDataImportRequest(operationElement, result);
                    break;
                case "BatchProcessRequest":
                    processBatchRequest(operationElement, result);
                    break;
                case "EntityQueryRequest":
                    processEntityQueryRequest(operationElement, result);
                    break;
                case "TransformRequest":
                    processTransformRequest(operationElement, result);
                    break;
                default:
                    processGenericRequest(operationElement, result);
                    break;
            }
        }
    }

    private void processDataImportRequest(Element requestElement, SOAPProcessingResult result) {
        result.setOperationType("DATA_IMPORT");
        List<DataEntity> entities = new ArrayList<>();

        // Process nested entity structures
        NodeList entityNodes = requestElement.getElementsByTagName("*");
        Element currentEntity = null;
        DataEntity dataEntity = null;

        for (int i = 0; i < entityNodes.getLength(); i++) {
            Node node = entityNodes.item(i);
            if (node.getNodeType() != Node.ELEMENT_NODE) continue;

            Element element = (Element) node;
            String tagName = element.getLocalName() != null ? element.getLocalName() : element.getTagName();

            if ("Entity".equals(tagName) || "Record".equals(tagName)) {
                if (dataEntity != null) {
                    entities.add(dataEntity);
                }
                dataEntity = new DataEntity();
                dataEntity.setType(element.getAttribute("type"));
                dataEntity.setId(element.getAttribute("id"));
                currentEntity = element;
                parseNestedEntity(element, dataEntity);
            }
        }

        if (dataEntity != null) {
            entities.add(dataEntity);
        }

        // Also handle flat structure imports
        if (entities.isEmpty()) {
            entities = parseFlatDataImport(requestElement);
        }

        // Process through data import processor
        DataImportResult importResult = dataImportProcessor.processEntities(entities);
        result.setImportResult(importResult);
        result.setRecordsProcessed(importResult.getSuccessCount());
        result.setStatus(importResult.hasErrors() ? "PARTIAL_SUCCESS" : "SUCCESS");

        if (importResult.hasErrors()) {
            importResult.getErrors().forEach(result::addError);
        }

        LOGGER.info("Data import processed: " + entities.size() + " entities");
    }

    private void parseNestedEntity(Element parentElement, DataEntity entity) {
        NodeList children = parentElement.getChildNodes();

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() != Node.ELEMENT_NODE) continue;

            Element childElement = (Element) child;
            String tagName = childElement.getLocalName() != null ? childElement.getLocalName() : childElement.getTagName();

            if (hasChildElements(childElement)) {
                // Nested complex entity
                DataEntity nestedEntity = new DataEntity();
                nestedEntity.setType(tagName);
                nestedEntity.setId(childElement.getAttribute("id"));
                parseNestedEntity(childElement, nestedEntity);
                entity.addNestedEntity(tagName, nestedEntity);
            } else {
                // Simple field
                String value = childElement.getTextContent().trim();
                entity.addField(tagName, value);

                // Process attributes
                NamedNodeMap attributes = childElement.getAttributes();
                for (int j = 0; j < attributes.getLength(); j++) {
                    Attr attr = (Attr) attributes.item(j);
                    entity.addField(tagName + "@" + attr.getName(), attr.getValue());
                }
            }
        }
    }

    private boolean hasChildElements(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return true;
            }
        }
        return false;
    }

    private List<DataEntity> parseFlatDataImport(Element requestElement) {
        List<DataEntity> entities = new ArrayList<>();
        NodeList children = requestElement.getChildNodes();

        DataEntity entity = new DataEntity();
        entity.setType("FlatRecord");

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) child;
                String tagName = element.getLocalName() != null ? element.getLocalName() : element.getTagName();
                entity.addField(tagName, element.getTextContent().trim());
            }
        }

        if (!entity.getFields().isEmpty()) {
            entities.add(entity);
        }

        return entities;
    }

    private void processBatchRequest(Element requestElement, SOAPProcessingResult result) {
        result.setOperationType("BATCH_PROCESS");
        List<DataEntity> batchEntities = new ArrayList<>();
        int batchSize = 0;

        // Parse batch configuration
        String batchId = getElementText(requestElement, "BatchId");
        String batchMode = getElementText(requestElement, "Mode");

        // Find all batch items
        NodeList batchItems = requestElement.getElementsByTagName("BatchItem");
        if (batchItems.getLength() == 0) {
            batchItems = requestElement.getElementsByTagName("Item");
        }

        for (int i = 0; i < batchItems.getLength(); i++) {
            Element batchItem = (Element) batchItems.item(i);
            DataEntity entity = new DataEntity();
            entity.setType("BatchItem");
            entity.setId(batchItem.getAttribute("id"));
            parseNestedEntity(batchItem, entity);
            batchEntities.add(entity);
            batchSize++;
        }

        // Process in configurable batch sizes
        int processingBatchSize = 100;
        int totalProcessed = 0;
        int totalErrors = 0;

        for (int i = 0; i < batchEntities.size(); i += processingBatchSize) {
            int end = Math.min(i + processingBatchSize, batchEntities.size());
            List<DataEntity> batch = batchEntities.subList(i, end);
            DataImportResult batchResult = dataImportProcessor.processEntities(batch);
            totalProcessed += batchResult.getSuccessCount();
            totalErrors += batchResult.getErrorCount();

            if (batchResult.hasErrors()) {
                batchResult.getErrors().forEach(result::addError);
            }
        }

        result.setRecordsProcessed(totalProcessed);
        result.setStatus(totalErrors > 0 ? "PARTIAL_SUCCESS" : "SUCCESS");
        result.addResponseData("batchId", batchId != null ? batchId : "auto-generated");
        result.addResponseData("totalItems", String.valueOf(batchSize));
        result.addResponseData("processedItems", String.valueOf(totalProcessed));
        result.addResponseData("errorItems", String.valueOf(totalErrors));

        LOGGER.info("Batch process completed: " + totalProcessed + "/" + batchSize + " items processed");
    }

    private void processEntityQueryRequest(Element requestElement, SOAPProcessingResult result) {
        result.setOperationType("ENTITY_QUERY");

        String entityType = getElementText(requestElement, "EntityType");
        String queryFilter = getElementText(requestElement, "Filter");
        String maxResults = getElementText(requestElement, "MaxResults");

        // Parse query criteria
        Map<String, String> criteria = new LinkedHashMap<>();
        NodeList criteriaNodes = requestElement.getElementsByTagName("Criterion");
        for (int i = 0; i < criteriaNodes.getLength(); i++) {
            Element criterion = (Element) criteriaNodes.item(i);
            String field = getElementText(criterion, "Field");
            String value = getElementText(criterion, "Value");
            String operator = criterion.getAttribute("operator");
            if (field != null && value != null) {
                criteria.put(field, (operator.isEmpty() ? "eq" : operator) + ":" + value);
            }
        }

        result.addResponseData("entityType", entityType != null ? entityType : "unknown");
        result.addResponseData("criteriaCount", String.valueOf(criteria.size()));
        result.addResponseData("filter", queryFilter != null ? queryFilter : "none");
        result.setStatus("SUCCESS");

        LOGGER.info("Entity query processed for type: " + entityType + " with " + criteria.size() + " criteria");
    }

    private void processTransformRequest(Element requestElement, SOAPProcessingResult result) {
        result.setOperationType("TRANSFORM");

        String sourceFormat = getElementText(requestElement, "SourceFormat");
        String targetFormat = getElementText(requestElement, "TargetFormat");

        // Process transformation mappings
        NodeList mappingNodes = requestElement.getElementsByTagName("Mapping");
        List<Map<String, String>> mappings = new ArrayList<>();

        for (int i = 0; i < mappingNodes.getLength(); i++) {
            Element mapping = (Element) mappingNodes.item(i);
            Map<String, String> mappingEntry = new LinkedHashMap<>();
            mappingEntry.put("source", getElementText(mapping, "Source"));
            mappingEntry.put("target", getElementText(mapping, "Target"));
            mappingEntry.put("transform", getElementText(mapping, "Transform"));
            mappings.add(mappingEntry);
        }

        // Process the payload data
        NodeList payloadNodes = requestElement.getElementsByTagName("Payload");
        if (payloadNodes.getLength() > 0) {
            Element payload = (Element) payloadNodes.item(0);
            DataEntity payloadEntity = new DataEntity();
            payloadEntity.setType("TransformPayload");
            parseNestedEntity(payload, payloadEntity);

            // Apply transformations
            DataEntity transformedEntity = applyTransformations(payloadEntity, mappings);
            result.addResponseData("transformedFields", String.valueOf(transformedEntity.getFields().size()));
        }

        result.addResponseData("sourceFormat", sourceFormat != null ? sourceFormat : "XML");
        result.addResponseData("targetFormat", targetFormat != null ? targetFormat : "XML");
        result.addResponseData("mappingCount", String.valueOf(mappings.size()));
        result.setStatus("SUCCESS");

        LOGGER.info("Transform processed: " + mappings.size() + " mappings");
    }

    private DataEntity applyTransformations(DataEntity source, List<Map<String, String>> mappings) {
        DataEntity transformed = new DataEntity();
        transformed.setType("TransformedEntity");

        for (Map<String, String> mapping : mappings) {
            String sourceField = mapping.get("source");
            String targetField = mapping.get("target");
            String transformType = mapping.get("transform");

            String value = source.getFields().get(sourceField);
            if (value != null) {
                String transformedValue = applyFieldTransform(value, transformType);
                transformed.addField(targetField != null ? targetField : sourceField, transformedValue);
            }
        }

        // Copy unmapped fields
        for (Map.Entry<String, String> entry : source.getFields().entrySet()) {
            if (!transformed.getFields().containsKey(entry.getKey())) {
                transformed.addField(entry.getKey(), entry.getValue());
            }
        }

        return transformed;
    }

    private String applyFieldTransform(String value, String transformType) {
        if (transformType == null || value == null) return value;

        switch (transformType.toUpperCase()) {
            case "UPPERCASE":
                return value.toUpperCase();
            case "LOWERCASE":
                return value.toLowerCase();
            case "TRIM":
                return value.trim();
            case "NORMALIZE":
                return value.replaceAll("\\s+", " ").trim();
            default:
                return value;
        }
    }

    private void processGenericRequest(Element requestElement, SOAPProcessingResult result) {
        result.setOperationType("GENERIC");

        DataEntity entity = new DataEntity();
        String tagName = requestElement.getLocalName() != null ? requestElement.getLocalName() : requestElement.getTagName();
        entity.setType(tagName);
        parseNestedEntity(requestElement, entity);

        result.addResponseData("elementType", tagName);
        result.addResponseData("fieldCount", String.valueOf(entity.getFields().size()));
        result.addResponseData("nestedEntityCount", String.valueOf(entity.getNestedEntities().size()));
        result.setStatus("SUCCESS");

        LOGGER.info("Generic request processed: " + tagName);
    }

    private String getElementText(Element parent, String tagName) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent().trim();
        }
        // Try with namespace
        NodeList nsNodes = parent.getElementsByTagNameNS("*", tagName);
        if (nsNodes.getLength() > 0) {
            return nsNodes.item(0).getTextContent().trim();
        }
        return null;
    }

    private String createSOAPResponse(SOAPProcessingResult result) {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>");
        sb.append("<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\" ");
        sb.append("xmlns:edi=\"http://enterprise.integration/edp\">");
        sb.append("<soap:Header>");
        sb.append("<edi:ProcessingInfo>");
        sb.append("<edi:ProcessingTimeMs>").append(result.getProcessingTimeMs()).append("</edi:ProcessingTimeMs>");
        sb.append("<edi:Timestamp>").append(System.currentTimeMillis()).append("</edi:Timestamp>");
        sb.append("</edi:ProcessingInfo>");
        sb.append("</soap:Header>");
        sb.append("<soap:Body>");
        sb.append("<edi:").append(result.getOperationType()).append("Response>");
        sb.append("<edi:Status>").append(escapeXml(result.getStatus())).append("</edi:Status>");
        sb.append("<edi:RecordsProcessed>").append(result.getRecordsProcessed()).append("</edi:RecordsProcessed>");

        // Response data
        if (!result.getResponseData().isEmpty()) {
            sb.append("<edi:ResponseData>");
            for (Map.Entry<String, String> entry : result.getResponseData().entrySet()) {
                sb.append("<edi:").append(entry.getKey()).append(">");
                sb.append(escapeXml(entry.getValue()));
                sb.append("</edi:").append(entry.getKey()).append(">");
            }
            sb.append("</edi:ResponseData>");
        }

        // Import results
        if (result.getImportResult() != null) {
            DataImportResult ir = result.getImportResult();
            sb.append("<edi:ImportSummary>");
            sb.append("<edi:TotalRecords>").append(ir.getTotalRecords()).append("</edi:TotalRecords>");
            sb.append("<edi:SuccessCount>").append(ir.getSuccessCount()).append("</edi:SuccessCount>");
            sb.append("<edi:ErrorCount>").append(ir.getErrorCount()).append("</edi:ErrorCount>");
            sb.append("</edi:ImportSummary>");
        }

        // Errors
        if (!result.getErrors().isEmpty()) {
            sb.append("<edi:Errors>");
            for (String error : result.getErrors()) {
                sb.append("<edi:Error>").append(escapeXml(error)).append("</edi:Error>");
            }
            sb.append("</edi:Errors>");
        }

        sb.append("</edi:").append(result.getOperationType()).append("Response>");
        sb.append("</soap:Body>");
        sb.append("</soap:Envelope>");

        return sb.toString();
    }

    private String createSOAPFault(String faultCode, String faultString) {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\">" +
                "<soap:Body>" +
                "<soap:Fault>" +
                "<faultcode>soap:" + escapeXml(faultCode) + "</faultcode>" +
                "<faultstring>" + escapeXml(faultString) + "</faultstring>" +
                "</soap:Fault>" +
                "</soap:Body>" +
                "</soap:Envelope>";
    }

    private String escapeXml(String input) {
        if (input == null) return "";
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;");
    }

    private void sendHttpResponse(OutputStream outputStream, int statusCode, String body) throws IOException {
        byte[] bodyBytes = body.getBytes("UTF-8");
        String statusText = statusCode == 200 ? "OK" : (statusCode == 400 ? "Bad Request" : "Internal Server Error");

        StringBuilder response = new StringBuilder();
        response.append("HTTP/1.1 ").append(statusCode).append(" ").append(statusText).append("\r\n");
        response.append("Content-Type: text/xml; charset=utf-8\r\n");
        response.append("Content-Length: ").append(bodyBytes.length).append("\r\n");
        response.append("Connection: close\r\n");
        response.append("\r\n");

        outputStream.write(response.toString().getBytes("UTF-8"));
        outputStream.write(bodyBytes);
        outputStream.flush();
    }

    // --- Inner Classes ---

    static class DataEntity {
        private String type;
        private String id;
        private Map<String, String> fields = new LinkedHashMap<>();
        private Map<String, List<DataEntity>> nestedEntities = new LinkedHashMap<>();

        public String getType() { return type; }
        public void setType(String type) { this.type = type; }
        public String getId() { return id; }
        public void setId(String id) { this.id = id; }
        public Map<String, String> getFields() { return fields; }
        public Map<String, List<DataEntity>> getNestedEntities() { return nestedEntities; }

        public void addField(String name, String value) {
            fields.put(name, value);
        }

        public void addNestedEntity(String name, DataEntity entity) {
            nestedEntities.computeIfAbsent(name, k -> new ArrayList<>()).add(entity);
        }

        @Override
        public String toString() {
            return "DataEntity{type='" + type + "', id='" + id + "', fields=" + fields.size() +
                    ", nested=" + nestedEntities.size() + "}";
        }
    }

    static class DataImportResult {
        private int totalRecords;
        private int successCount;
        private int errorCount;
        private List<String> errors = new ArrayList<>();
        private List<String> processedIds = new ArrayList<>();

        public int getTotalRecords() { return totalRecords; }
        public void setTotalRecords(int totalRecords) { this.totalRecords = totalRecords; }
        public int getSuccessCount() { return successCount; }
        public void setSuccessCount(int successCount) { this.successCount = successCount; }
        public int getErrorCount() { return errorCount; }
        public void setErrorCount(int errorCount) { this.errorCount = errorCount; }
        public List<String> getErrors() { return errors; }
        public List<String> getProcessedIds() { return processedIds; }
        public boolean hasErrors() { return !errors.isEmpty(); }

        public void addError(String error) { errors.add(error); }
        public void addProcessedId(String id) { processedIds.add(id); }
    }

    static class DataImportProcessor {
        private static final Logger LOGGER = Logger.getLogger(DataImportProcessor.class.getName());

        public DataImportResult processEntities(List<DataEntity> entities) {
            DataImportResult result = new DataImportResult();
            result.setTotalRecords(entities.size());
            int success = 0;
            int errors = 0;

            for (DataEntity entity : entities) {
                try {
                    validateEntity(entity);
                    persistEntity(entity);
                    success++;
                    if (entity.getId() != null && !entity.getId().isEmpty()) {
                        result.addProcessedId(entity.getId());
                    }
                } catch (Exception e) {
                    errors++;
                    result.addError("Failed to process entity [" + entity.getType() +
                            ":" + entity.getId() + "]: " + e.getMessage());
                    LOGGER.log(Level.WARNING, "Entity processing failed", e);
                }
            }

            result.setSuccessCount(success);
            result.setErrorCount(errors);
            return result;
        }

        private void validateEntity(DataEntity entity) throws Exception {
            if (entity.getType() == null || entity.getType().isEmpty()) {
                throw new Exception("Entity type is required");
            }
            // Add custom validation rules
            for (Map.Entry<String, String> field : entity.getFields().entrySet()) {
                if (field.getValue() != null && field.getValue().length() > 10000) {
                    throw new Exception("Field '" + field.getKey() + "' exceeds maximum length");
                }
            }
        }

        private void persistEntity(DataEntity entity) {
            // Simulate persistence - in production, this would write to database
            LOGGER.fine("Persisting entity: " + entity);

            // Process nested entities recursively
            for (Map.Entry<String, List<DataEntity>> nestedEntry : entity.getNestedEntities().entrySet()) {
                for (DataEntity nested : nestedEntry.getValue()) {
                    persistEntity(nested);
                }
            }
        }
    }

    static class SOAPProcessingResult {
        private String status = "UNKNOWN";
        private String operationType = "UNKNOWN";
        private int recordsProcessed;
        private long processingTimeMs;
        private Map<String, String> headerInfo = new LinkedHashMap<>();
        private Map<String, String> responseData = new LinkedHashMap<>();
        private List<String> errors = new ArrayList<>();
        private DataImportResult importResult;

        public String getStatus() { return status; }
        public void setStatus(String status) { this.status = status; }
        public String getOperationType() { return operationType; }
        public void setOperationType(String operationType) { this.operationType = operationType; }
        public int getRecordsProcessed() { return recordsProcessed; }
        public void setRecordsProcessed(int recordsProcessed) { this.recordsProcessed = recordsProcessed; }
        public long getProcessingTimeMs() { return processingTimeMs; }
        public void setProcessingTimeMs(long processingTimeMs) { this.processingTimeMs = processingTimeMs; }
        public Map<String, String> getHeaderInfo() { return headerInfo; }
        public void setHeaderInfo(Map<String, String> headerInfo) { this.headerInfo = headerInfo; }
        public Map<String, String> getResponseData() { return responseData; }
        public List<String> getErrors() { return errors; }
        public DataImportResult getImportResult() { return importResult; }
        public void setImportResult(DataImportResult importResult) { this.importResult = importResult; }

        public void addError(String error) { errors.add(error); }
        public void addResponseData(String key, String value) { responseData.put(key, value); }
    }

    static class XMLErrorHandler implements org.xml.sax.ErrorHandler {
        private static final Logger LOGGER = Logger.getLogger(XMLErrorHandler.class.getName());

        @Override
        public void warning(org.xml.sax.SAXParseException exception) {
            LOGGER.warning("XML Parse Warning: " + exception.getMessage());
        }

        @Override
        public void error(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Parse Error: " + exception.getMessage());
            throw exception;
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException exception) throws SAXException {
            LOGGER.severe("XML Fatal Error: " + exception.getMessage());
            throw exception;
        }
    }

    // --- Client utility for testing ---

    public static class SOAPClient {
        public static String sendSOAPRequest(String host, int port, String soapAction, String soapXml) throws IOException {
            Socket socket = new Socket(host, port);
            byte[] bodyBytes = soapXml.getBytes("UTF-8");

            StringBuilder request = new StringBuilder();
            request.append("POST / HTTP/1.1\r\n");
            request.append("Host: ").append(host).append(":").append(port).append("\r\n");
            request.append("Content-Type: text/xml; charset=utf-8\r\n");
            request.append("SOAPAction: \"").append(soapAction).append("\"\r\n");
            request.append("Content-Length: ").append(bodyBytes.length).append("\r\n");
            request.append("Connection: close\r\n");
            request.append("\r\n");

            OutputStream out = socket.getOutputStream();
            out.write(request.toString().getBytes("UTF-8"));
            out.write(bodyBytes);
            out.flush();

            BufferedReader reader = new BufferedReader(new InputStreamReader(socket.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line).append("\n");
            }

            socket.close();
            return response.toString();
        }
    }

    // --- Main entry point ---

    public static void main(String[] args) {
        int port = 8080;
        int threadPoolSize = 10;

        if (args.length > 0) {
            port = Integer.parseInt(args[0]);
        }
        if (args.length > 1) {
            threadPoolSize = Integer.parseInt(args[1]);
        }

        EnterpriseSOAPService service = new EnterpriseSOAPService(threadPoolSize);

        // Add shutdown hook
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down Enterprise SOAP Service...");
            service.stop();
        }));

        // Demo: process a sample SOAP message directly
        String sampleSOAP = buildSampleSOAPMessage();
        LOGGER.info("Processing sample SOAP message...");
        SOAPProcessingResult result = service.processSOAPMessage(sampleSOAP);
        LOGGER.info("Sample result - Status: " + result.getStatus() +
                ", Operation: " + result.getOperationType() +
                ", Records: " + result.getRecordsProcessed() +
                ", Time: " + result.getProcessingTimeMs() + "ms");

        // Start server
        try {
            LOGGER.info("Starting Enterprise SOAP Service on port " + port);
            service.start(port);
        } catch (IOException e) {
            LOGGER.log(Level.SEVERE, "Failed to start service", e);
            System.exit(1);
        }
    }

